SELECT COUNT(DISTINCT code_id) 
FROM document_codes
WHERE doc_id = 0;

SELECT 
  (SELECT COUNT(DISTINCT doc_id) FROM documents WHERE created_by = 1) AS total_documents,
  (SELECT COUNT(DISTINCT code_id) FROM control_codes WHERE created_by = 1) AS total_control_codes;

SELECT DISTINCT code_id
FROM code_usage
WHERE usage_context = 'Conversion';

SELECT COUNT(*) 
FROM code_usage 
WHERE usage_context IN ('Digital', 'Mobile', 'Conversion');

SELECT doc_id
FROM document_codes
WHERE notes = 'Used in text layout';

SELECT category_id, category_name
FROM code_categories
WHERE parent_category_id IS NOT NULL;
